export * as ScrollArea from "./namespace";
export * from "./scroll-area";
export * from "./styles";

"use client";

import { ScrollArea } from "@base-ui/react/scroll-area";
import { composeRenderProps } from "react-aria-components";
import { ScrollAreaStyles } from "./styles";

export interface ScrollAreaRootProps
  extends React.ComponentProps<typeof ScrollArea.Root> {}

export function ScrollAreaRoot({ className, ...props }: ScrollAreaRootProps) {
  return (
    <ScrollArea.Root
      {...props}
      className={composeRenderProps(className, (className) =>
        ScrollAreaStyles.Root({ className })
      )}
      data-slot="scroll-area-root"
    />
  );
}

export interface ScrollAreaViewportProps
  extends React.ComponentProps<typeof ScrollArea.Viewport> {
  scrollFade?: boolean;
  scrollbarGutter?: boolean;
}

export function ScrollAreaViewport({
  className,
  scrollFade = false,
  scrollbarGutter = false,
  ...props
}: ScrollAreaViewportProps) {
  return (
    <ScrollArea.Viewport
      {...props}
      className={composeRenderProps(className, (className) =>
        ScrollAreaStyles.Viewport({ className, scrollFade, scrollbarGutter })
      )}
      data-slot="scroll-area-viewport"
    />
  );
}

export interface ScrollAreaScrollbarProps
  extends React.ComponentProps<typeof ScrollArea.Scrollbar> {
}

export function ScrollAreaScrollbar({
  className,
  orientation,
  ...props
}: ScrollAreaScrollbarProps) {
  return (
    <ScrollArea.Scrollbar
      {...props}
      className={composeRenderProps(className, (className) =>
        ScrollAreaStyles.Scrollbar({ className, orientation })
      )}
      orientation={orientation}
      data-slot="scroll-area-scrollbar"
    />
  );
}

export interface ScrollAreaThumbProps
  extends React.ComponentProps<typeof ScrollArea.Thumb> {}

export function ScrollAreaThumb({ className, ...props }: ScrollAreaThumbProps) {
  return (
    <ScrollArea.Thumb
      {...props}
      className={composeRenderProps(className, (className) =>
        ScrollAreaStyles.Thumb({ className })
      )}
      data-slot="scroll-area-thumb"
    />
  );
}

import { cva } from "~/registry/lib/cva";

export const ScrollAreaStyles = {
  Root: cva({
    base: ["size-full min-h-0"],
  }),
  Scrollbar: cva({
    base: [
      "m-1 flex opacity-0 transition-opacity delay-300",
      "data-hovering:opacity-100 data-scrolling:opacity-100",
      "data-hovering:delay-0 data-scrolling:delay-0",
      "data-hovering:duration-100 data-scrolling:duration-100",
    ],
    variants: {
      orientation: {
        horizontal: ["h-1.5 flex-col"],
        vertical: ["w-1.5"],
      },
    },
  }),
  Thumb: cva({
    base: ["relative flex-1 rounded-full bg-foreground/20"],
  }),
  Viewport: cva({
    base: [
      "h-full overscroll-contain rounded-[inherit] outline-none transition-shadows",
      "focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-1 focus-visible:ring-offset-background",
    ],
    variants: {
      scrollFade: {
        true: [
          "mask-t-from-[calc(100%-min(var(--fade-size),var(--scroll-area-overflow-y-start)))]",
          "mask-b-from-[calc(100%-min(var(--fade-size),var(--scroll-area-overflow-y-end)))]",
          "mask-l-from-[calc(100%-min(var(--fade-size),var(--scroll-area-overflow-x-start)))]",
          "mask-r-from-[calc(100%-min(var(--fade-size),var(--scroll-area-overflow-x-end)))]",
          "[--fade-size:1.5rem]",
        ],
        false: [],
      },
      scrollbarGutter: {
        true: ["data-has-overflow-y:pe-2.5 data-has-overflow-x:pb-2.5"],
        false: [],
      },
    },
    defaultVariants: {
      scrollFade: false,
      scrollbarGutter: false,
    },
  }),
};

export {
  ScrollAreaRoot as Root,
  ScrollAreaScrollbar as Scrollbar,
  ScrollAreaThumb as Thumb,
  ScrollAreaViewport as Viewport,
} from "./scroll-area";
